using System.ComponentModel.DataAnnotations;

namespace sv_51470e6e645d4e69bd0eb7fd8cc29b8c.Models;

public class AppointmentFormModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone number is required.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string? InsuranceProvider { get; set; }

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string? Doctor { get; set; }

    [Required(ErrorMessage = "Appointment date is required.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string? TimeSlot { get; set; }

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string? ReasonForVisit { get; set; }
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateOnly date && date <= DateOnly.FromDateTime(DateTime.Today))
        {
            return new ValidationResult("Date must be in the future.");
        }
        return ValidationResult.Success;
    }
}

namespace sv_51470e6e645d4e69bd0eb7fd8cc29b8c.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors = new()
    {
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Williams",
        "Dr. Patel"
    };

    private static readonly Dictionary<string, List<string>> DoctorSlots = new()
    {
        ["Dr. Smith"] = new() { "9:00 AM", "10:00 AM", "11:00 AM", "2:00 PM", "3:00 PM" },
        ["Dr. Johnson"] = new() { "8:00 AM", "10:00 AM", "1:00 PM", "4:00 PM" },
        ["Dr. Williams"] = new() { "9:30 AM", "11:30 AM", "2:30 PM", "4:30 PM" },
        ["Dr. Patel"] = new() { "8:30 AM", "10:00 AM", "12:00 PM", "3:30 PM" }
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>(Doctors));
    }

    public Task<List<string>> GetAvailableSlotsAsync(string doctor, DateOnly date)
    {
        if (DoctorSlots.TryGetValue(doctor, out var slots))
        {
            return Task.FromResult(new List<string>(slots));
        }
        return Task.FromResult(new List<string>());
    }

    /// <summary>
    /// Validates server-side business rules. Returns a dictionary of field name → error messages.
    /// </summary>
    public Task<Dictionary<string, List<string>>> ValidatePatientAsync(
        string? email, string? insuranceProvider, string? doctor, string? timeSlot)
    {
        var errors = new Dictionary<string, List<string>>();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(email)] = new() { "Account has outstanding balance" };
        }

        // Reject "None" insurance with Dr. Smith (doesn't accept self-pay)
        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal)
            && string.Equals(doctor, "Dr. Smith", StringComparison.Ordinal))
        {
            errors[nameof(doctor)] = new() { "Selected doctor does not accept self-pay patients" };
        }

        // Reject "10:00 AM" as taken (simulated race condition)
        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            errors[nameof(timeSlot)] = new() { "This slot is no longer available" };
        }

        return Task.FromResult(errors);
    }

    public Task<bool> BookAppointmentAsync()
    {
        // Stub: always succeeds
        return Task.FromResult(true);
    }
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Forms;

namespace sv_51470e6e645d4e69bd0eb7fd8cc29b8c.Components;

public class CustomValidator : ComponentBase
{
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}

