                <div class="mb-3">
                    <label class="form-label" for="doctor">Preferred Doctor</label>
                    <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor"
                                 @bind-Value:after="OnDoctorChanged">
                        <option value="">-- Select --</option>
                        @foreach (var doc in doctors)
                        {
                            <option value="@doc">@doc</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.Doctor" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="date">Date</label>
                    <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate"
                               @bind-Value:after="OnDateChanged" />
                    <ValidationMessage For="() => Model.AppointmentDate" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="timeSlot">Time Slot</label>
                    <InputSelect id="timeSlot" class="form-select" @bind-Value="Model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in availableSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.TimeSlot" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="reason">Reason for Visit</label>
                    <InputTextArea id="reason" class="form-control" @bind-Value="Model.ReasonForVisit" rows="3" />
                    <ValidationMessage For="() => Model.ReasonForVisit" />
                    @if (Model.ReasonForVisit is not null)
                    {
                        <small class="text-muted">@Model.ReasonForVisit.Length / 500</small>
                    }
                </div>

                <button type="button" class="btn btn-info me-2" @onclick="CheckAvailability" disabled="@isSubmitting">
                    @(isSubmitting ? "Checking..." : "Check Availability")
                </button>
                <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked || isSubmitting)">
                    Book Appointment
                </button>
            </fieldset>
        }
    </EditForm>
}

@code {
    private AppointmentFormModel Model = new();
    private EditContext editContext = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isBooked;
    private bool isSubmitting;
    private bool availabilityChecked;

    private List<string> doctors = new();
    private List<string> availableSlots = new();

    // Fields that belong to step 1 for partial validation
    private static readonly string[] Step1Fields =
        { nameof(AppointmentFormModel.PatientName), nameof(AppointmentFormModel.Email),
          nameof(AppointmentFormModel.Phone), nameof(AppointmentFormModel.InsuranceProvider) };

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step 1 fields
        var isValid = true;
        foreach (var field in Step1Fields)
        {
            var fi = editContext.Field(field);
            editContext.NotifyFieldChanged(fi);
        }

        // Check if step 1 fields have any validation errors
        editContext.Validate();
        foreach (var field in Step1Fields)
        {
            if (editContext.GetValidationMessages(editContext.Field(field)).Any())
            {
                isValid = false;
            }
        }

        if (isValid)
        {
            showStep2 = true;
        }
    }

    private async Task OnDoctorChanged()
    {
        availabilityChecked = false;
        Model.TimeSlot = null;
        await LoadSlots();
    }

    private async Task OnDateChanged()
    {
        availabilityChecked = false;
        Model.TimeSlot = null;
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
        else
        {
            availableSlots = new();
        }
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        availabilityChecked = false;

        // Validate the full form via data annotations first
        if (!editContext.Validate())
        {
            return;
        }

        isSubmitting = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            availabilityChecked = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (!availabilityChecked)
            return;

        customValidator?.ClearErrors();

        if (!editContext.Validate())
            return;

        // Re-run server validation on final submit
        var errors = await AppointmentSvc.ValidatePatientAsync(
            Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);

        if (errors.Count > 0)
        {
            customValidator!.DisplayErrors(errors);
            availabilityChecked = false;
            return;
        }

        await AppointmentSvc.BookAppointmentAsync();
        isBooked = true;
    }
}

