+    }
+
+    private async Task OnDateChanged()
+    {
+        availabilityChecked = false;
+        Model.TimeSlot = null;
+        await LoadSlots();
+    }
+
+    private async Task LoadSlots()
+    {
+        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
+        {
+            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
+                Model.Doctor, Model.AppointmentDate.Value);
+        }
+        else
+        {
+            availableSlots = new();
+        }
+    }
+
+    private async Task CheckAvailability()
+    {
+        customValidator?.ClearErrors();
+        availabilityChecked = false;
+
+        // Validate the full form via data annotations first
+        if (!editContext.Validate())
+        {
+            return;
+        }
+
+        isSubmitting = true;
+        try
+        {
+            var errors = await AppointmentSvc.ValidatePatientAsync(
+                Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);
+
+            if (errors.Count > 0)
+            {
+                customValidator!.DisplayErrors(errors);
+                return;
+            }
+
+            availabilityChecked = true;
+        }
+        finally
+        {
+            isSubmitting = false;
+        }
+    }
+
+    private async Task HandleSubmit()
+    {
+        if (!availabilityChecked)
+            return;
+
+        customValidator?.ClearErrors();
+
+        if (!editContext.Validate())
+            return;
+
+        // Re-run server validation on final submit
+        var errors = await AppointmentSvc.ValidatePatientAsync(
+            Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);
+
+        if (errors.Count > 0)
+        {
+            customValidator!.DisplayErrors(errors);
+            availabilityChecked = false;
+            return;
+        }
+
+        await AppointmentSvc.BookAppointmentAsync();
+        isBooked = true;
+    }
+}
